068f4e32  	name: string;
62c158e7  	chat(req: unknown, signal?: AbortSignal): Promise<unknown>;
d10b36aa  }
e3b0c442  
2a9c461c  export function registerEmmyProvider(
69498de0  	pi: { registerProvider: (name: string, impl: PiProviderImpl) => void },
fb3a4e1d  	profile: ProfileSnapshot,
9c351759  	opts: { baseUrl?: string; turnIdProvider?: () => string } = {},
