415ca577  				payload,
31b74185  				profile,
c5cbcf68  				{ turnId: opts.turnIdProvider?.() },
cdf704fc  			);
c6008beb  			for (const c of response.choices) {
146f59b5  				stripNonStandardFields(
edb73c82  					c.message as unknown as Record<string, unknown>,
3800e01d  					profile.serving.quirks,
ba9e6098  				);
4ffaefcc  			}
f4704868  			return response;
b7fa8888  		},
eeb33785  	});
d10b36aa  }
e3b0c442  
