628db88c  function shapeRequest(req: ChatRequest, profile: ProfileSnapshot): ChatRequest {
8f1033aa  	const samp = profile.serving.sampling_defaults;
975d15d2  	return {
5e1200b9  		...req,
ea21200e  		model: profile.serving.engine.served_model_name,
33aa2f2f  		temperature: req.temperature ?? samp.temperature,
ab325de5  		top_p: req.top_p ?? samp.top_p,
42febc3c  		max_tokens: req.max_tokens ?? samp.max_tokens,
1d6bc606  		stop: req.stop ?? samp.stop,
d5130ff6  	};
d10b36aa  }

