7a831597  			const text = await resp.text().catch(() => "(unreadable body)");
dbdbdd1f  			throw new NetworkError(url, resp.status, text.slice(0, 512));
3713bbfd  		}
0bdce2cf  		return (await resp.json()) as ChatResponse;
2959c032  	} catch (e: unknown) {
52447d86  		if (e instanceof NetworkError) throw e;
8ac2d31a  		if (
061cade0  			e instanceof Error &&
1ef68a6f  			(e.name === "AbortError" ||
49987521  				e.name === "TimeoutError" ||
1d9ccaff  				/timeout/i.test(e.message))
883ac9b7  		) {
576acc81  			throw new NetworkError(url, null, `timeout after ${timeoutMs}ms`);
3713bbfd  		}
29fdc5c9  		throw new NetworkError(
