6b50f7a1  //   retry (D-11); never on the first call.
a2c23396  //
fd7c1338  // Timeouts: default 120s matches `replay.py`; the SP_OK canary caller passes
6d441ba5  // 60000ms per `sp_ok.py`.
e3b0c442  
4605332f  import { NetworkError } from "./errors";
75a9308f  import type { ChatRequest, ChatResponse } from "./types";
e3b0c442  
9b4b8c14  export async function postChat(
3fc75565  	baseUrl: string,
93cd6f2b  	payload: ChatRequest,
db18feff  	opts: { timeoutMs?: number } = {},
f7bbd09b  ): Promise<ChatResponse> {
eb45b7fc  	const url = `${baseUrl.replace(/\/$/, "")}/v1/chat/completions`;
9d583544  	const timeoutMs = opts.timeoutMs ?? 120_000;
99ca39aa  	const controller = new AbortController();
8f9a52ee  	const timer = setTimeout(() => {
ce1d447b  		// AbortController.abort(reason) exists on modern runtimes; fall back gracefully.
131bbee0  		try {
66455ff5  			(controller as AbortController & { abort: (reason?: unknown) => void }).abort(
e2d0e426  				new Error("timeout"),
cdf704fc  			);
3dbe4bd7  		} catch (_e) {
346c162f  			controller.abort();
3713bbfd  		}
b8aa8589  	}, timeoutMs);
debaf31e  	try {
14a431d0  		const resp = await fetch(url, {
65680448  			method: "POST",
a650aae9  			headers: { "content-type": "application/json" },
2ae16f29  			body: JSON.stringify(payload),
03c0f11f  			signal: controller.signal,
206aa438  		});
0e23e21f  		if (!resp.ok) {
7a831597  			const text = await resp.text().catch(() => "(unreadable body)");
dbdbdd1f  			throw new NetworkError(url, resp.status, text.slice(0, 512));
3713bbfd  		}
0bdce2cf  		return (await resp.json()) as ChatResponse;
2959c032  	} catch (e: unknown) {
52447d86  		if (e instanceof NetworkError) throw e;
8ac2d31a  		if (
061cade0  			e instanceof Error &&
1ef68a6f  			(e.name === "AbortError" ||
49987521  				e.name === "TimeoutError" ||
1d9ccaff  				/timeout/i.test(e.message))
883ac9b7  		) {
576acc81  			throw new NetworkError(url, null, `timeout after ${timeoutMs}ms`);
3713bbfd  		}
29fdc5c9  		throw new NetworkError(
b62303bf  			url,
035aecc0  			null,
4cb9d120  			e instanceof Error ? e.message : String(e),
80e5ba03  		);
bc9be798  	} finally {
e1f2f5bf  		clearTimeout(timer);
a32a3bb7  	}
d10b36aa  }
