f0def744  	profilePath: string,
61ade9a3  ): Promise<Record<string, SubAgentSpec>> {
481d66e7  	const harnessPath = join(profilePath, "harness.yaml");
888ee6c4  	if (!existsSync(harnessPath)) {
d8f530ad  		throw new PersonaLoadError(
79f8fe6f  			"no_subagents_block",
2e7d8855  			`harness.yaml not found at ${harnessPath}`,
80e5ba03  		);
