7a90833f  			if (realRel.startsWith("..") || isAbsolute(realRel)) {
7afcf884  				throw new PersonaLoadError(
030c270a  					"path_traversal",
3a1a23fe  					`persona "${personaSlug}" persona_dir realpath escapes profile root: ${realResolved}`,
a1008c9b  					personaSlug,
ba9e6098  				);
4ffaefcc  			}
8512ee4d  			let stat;
bddb3c5e  			try {
06ed3fda  				stat = statSync(realResolved);
ef768074  			} catch {
