13451c96  		const spec: SubAgentSpec = {
9f06c1df  			name: personaSlug,
f4944ac6  			description: entry.description,
f1abfaef  			pattern: entry.pattern,
86d479a9  			personaDir,
8fb5b7d5  			agentsContent,
68f0733d  			toolAllowlist: entry.tool_allowlist as string[],
f4952db4  			modelOverride:
dd634895  				typeof entry.model_override === "string" && entry.model_override.length > 0
